# Dictionary xüsusiyyətləri
person = {'name': 'Ali', 'age': 25}
person['city'] = 'Bakı'  # Yeni açar-dəyər əlavəsi
person['age'] = 26  # Dəyər dəyişdirilməsi
print(f'Yeni dictionary: {person}')
try:
    person[[1, 2]] = 'list'  # Siyahı açar ola bilməz
except TypeError:
    print('Xəta: Açar dəyişməz olmalıdır!')

# for dövrü ilə dictionary
person = {'name': 'Ali', 'age': 25, 'city': 'Bakı'}
# Açarlar üzərində
for key in person:
    print(f'Açar: {key}')
# Dəyərlər üzərində
for value in person.values():
    print(f'Dəyər: {value}')
# Açar-dəyər cütləri üzərində
for key, value in person.items():
    print(f'Açar: {key}, Dəyər: {value}')

# Python kodu
person = {'name': 'Ali', 'age': 25}
print(person)

// JavaScript kodu
const person = {name: 'Ali', age: 25};
console.log(person);

# Səhv idarəetməsi
person = {'name': 'Ali', 'age': 25}
# Açar yoxluğu
print(f'Şəhər: {person.get('city', 'Tapılmadı')}')
# Səhv açar tipi
try:
    person[[1, 2]] = 'list'
except TypeError:
    print('Xəta: Açar dəyişməz olmalıdır!')
# Mövcudluğun yoxlanması
if 'name' in person:
    print(f'Açar mövcuddur: {person['name']}')

# Dictionary properties
person = {'name': 'Ali', 'age': 25}
person['city'] = 'Baku'  # Adding a new key-value pair
person['age'] = 26  # Modifying a value
print(f'Updated dictionary: {person}')
try:
    person[[1, 2]] = 'list'  # Lists cannot be keys
except TypeError:
    print('Error: Keys must be immutable!')

# Dictionaries with for loop
person = {'name': 'Ali', 'age': 25, 'city': 'Baku'}
# Over keys
for key in person:
    print(f'Key: {key}')
# Over values
for value in person.values():
    print(f'Value: {value}')
# Over key-value pairs
for key, value in person.items():
    print(f'Key: {key}, Value: {value}')

# Python code
person = {'name': 'Ali', 'age': 25}
print(person)

// JavaScript code
const person = {name: 'Ali', age: 25};
console.log(person);

# Error handling
person = {'name': 'Ali', 'age': 25}
# Key absence
print(f'City: {person.get('city', 'Not found')}')
# Invalid key type
try:
    person[[1, 2]] = 'list'
except TypeError:
    print('Error: Keys must be immutable!')
# Existence check
if 'name' in person:
    print(f'Key exists: {person['name']}')

# Свойства словарей
person = {'name': 'Али', 'age': 25}
person['city'] = 'Баку'  # Добавление новой пары ключ-значение
person['age'] = 26  # Изменение значения
print(f'Обновленный словарь: {person}')
try:
    person[[1, 2]] = 'list'  # Список не может быть ключом
except TypeError:
    print('Ошибка: Ключи должны быть неизменяемыми!')

# Словари с циклом for
person = {'name': 'Али', 'age': 25, 'city': 'Баку'}
# По ключам
for key in person:
    print(f'Ключ: {key}')
# По значениям
for value in person.values():
    print(f'Значение: {value}')
# По парам ключ-значение
for key, value in person.items():
    print(f'Ключ: {key}, Значение: {value}')

# Код Python
person = {'name': 'Али', 'age': 25}
print(person)

// Код JavaScript
const person = {name: 'Али', age: 25};
console.log(person);

# Обработка ошибок
person = {'name': 'Али', 'age': 25}
# Отсутствие ключа
print(f'Город: {person.get('city', 'Не найдено')}')
# Неверный тип ключа
try:
    person[[1, 2]] = 'list'
except TypeError:
    print('Ошибка: Ключи должны быть неизменяемыми!')
# Проверка наличия
if 'name' in person:
    print(f'Ключ существует: {person['name']}')
